# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from web3 import Web3
from flask import Flask, request, jsonify

app = Flask(__name__)

# Ethereum provider URL
provider_url = "YOUR_PROVIDER_URL"

# Initialize Web3
w3 = Web3(Web3.HTTPProvider(provider_url))

@app.route("/verify_signature", methods=["POST"])
def verify_signature():
    # Get signed message and signature from request
    data = request.json
    signed_message = data["signed_message"]
    signature = data["signature"]

    # Get public address from signature
    address = w3.eth.account.recover_message(signed_message.encode("utf-8"), signature)

    # Return the authenticated address
    return jsonify({"address": address})

if __name__ == "__main__":
    app.run(debug=True)